parameters.jsCode:
// Validate and extract onboarding data
const data = $input.first().json.body;

// Required fields validation
const required = ['restaurant_name', 'owner_name', 'owner_email', 'tier', 'timezone'];
const missing = required.filter(field => !data[field]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Validate tier
if (!['Starter', 'Pro'].includes(data.tier)) {
  throw new Error('Invalid tier. Must be "Starter" or "Pro"');
}

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(data.owner_email)) {
  throw new Error('Invalid email format');
}

// Generate unique restaurant ID
const crypto = require('crypto');
const restaurantId = `rest_${crypto.randomBytes(8).toString('hex')}`;

// Prepare restaurant data
return [{
  json: {
    restaurant_id: restaurantId,
    restaurant_name: data.restaurant_name,
    owner_name: data.owner_name,
    owner_email: data.owner_email,
    phone_number: data.phone_number || null,
    address: data.address || null,
    timezone: data.timezone || 'America/New_York',
    tier: data.tier,

    // Brand voice data (if Pro)
    brand_voice: data.tier === 'Pro' ? {
      personality: data.personality || 'Professional',
      tone: data.tone || 'Professional but Warm',
      emoji_usage: data.emoji_usage || 'Rarely',
      self_reference: data.self_reference || 'We',
      owner_name_for_responses: data.owner_name_for_responses || null,
      response_length_preference: data.response_length_preference || 'Moderate',
      signature_phrases: data.signature_phrases || [],
      prohibited_words: data.prohibited_words || [],
      policies_to_mention: data.policies_to_mention || {},
      contact_info_for_complaints: data.contact_info_for_complaints || null,
      example_responses: data.example_responses || []
    } : null,

    // Onboarding metadata
    onboarding_step: 'google_oauth',
    created_at: new Date().toISOString(),
    status: 'Onboarding'
  }
}];

